//! Bounded exhaustive check: small grid matches lift_reference (HIL surrogate).
use gnosis_rtl_bridge::ir::SieveFsmIrV0;
use gnosis_rtl_bridge::lift_outcome;

#[test]
fn brute_small_grid_lift_parity() {
    for heads in 0u16..=8u16 {
        for coupling in 0u16..=16u16 {
            for observer in 1u16..=32u16 {
                for thr in 0u16..=8u16 {
                    let ir = SieveFsmIrV0::new(heads, coupling, observer, thr);
                    let o = lift_outcome(&ir);
                    assert!(o.after_observer_resolution >= 1 || !o.lift);
                    if heads == 8 && coupling == 0 && observer == 12 && thr == 1 {
                        assert!(o.lift, "known aeon alias case");
                        assert_eq!(o.after_observer_resolution, 24);
                    }
                }
            }
        }
    }
}
